import { useState, useEffect } from "react";
import { useSelector } from "react-redux";
import { Link } from "react-router-dom";
import { toast } from "react-toastify";

function Courses() {
  const [courses, setCourses] = useState([]);
  const user = useSelector((state) => state.auth.user);

  useEffect(() => {
    fetch("http://localhost:3001/courses")
      .then((res) => res.json())
      .then((data) => setCourses(data))
      .catch((error) => toast.error("Ошибка загрузки курсов"));
  }, []);

  async function handleDelete(courseId) {
    try {
      const enrollmentsResponse = await fetch(`http://localhost:3001/enrollments?courseId=${courseId}`);
      const enrollments = await enrollmentsResponse.json();
      for (const enrollment of enrollments) {
        await fetch(`http://localhost:3001/enrollments/${enrollment.id}`, { method: "DELETE" });
      }
      const filesResponse = await fetch(`http://localhost:3001/files?courseId=${courseId}`);
      const files = await filesResponse.json();
      for (const file of files) {
        await fetch(`http://localhost:3001/files/${file.id}`, { method: "DELETE" });
      }
      const notificationsResponse = await fetch(`http://localhost:3001/notifications`);
      const notifications = await notificationsResponse.json();
      for (const notification of notifications) {
        if (notification.message.includes(`Курс ${courses.find(c => c.id === courseId)?.name}`) ||
            notification.message.includes(`Записан на ${courses.find(c => c.id === courseId)?.name}`)) {
          await fetch(`http://localhost:3001/notifications/${notification.id}`, { method: "DELETE" });
        }
      }
      const response = await fetch(`http://localhost:3001/courses/${courseId}`, {
        method: "DELETE",
      });

      if (response.ok) {
        setCourses(courses.filter((course) => course.id !== courseId));
        toast.success("Курс успешно удален!");
      } else {
        toast.error("Не удалось удалить курс");
      }
    } catch (error) {
      toast.error("Сетевая ошибка при удалении курса");
    }
  }

  return (
    <div className="container mt-5">
      <h1 className="mb-4">Доступные курсы</h1>
      {user?.role === "teacher" && (
        <div className="mb-4">
          <Link to="/add-course" className="btn btn-success">
            Добавить курс
          </Link>
        </div>
      )}
      <ul className="list-group">
        {courses.map((course) => (
          <li key={course.id} className="list-group-item d-flex justify-content-between align-items-center">
            <span>{course.name}</span>
            {user?.role === "teacher" && parseInt(course.teacherId) === parseInt(user.id) && (
              <div>
                <Link to={`/edit-course/${course.id}`} className="btn btn-warning btn-sm me-2">
                  Редактировать
                </Link>
                <button
                  onClick={() => handleDelete(course.id)}
                  className="btn btn-danger btn-sm"
                >
                  Удалить
                </button>
              </div>
            )}
          </li>
        ))}
      </ul>
    </div>
  );
}

export default Courses;
